/*
输入e[i].x和e[i].y
对e进行排序
初始化d[n+1]
循环遍历1~n
	循环遍历
		e[a[m]].p = i
	a[++m]=i
输出c() 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
const int kMaxN = 5e4 + 2;
struct E {
  	int x, y, p;
  	bool operator <(const E &_e) const {
	  	return x < _e.x;
	}
} e[kMaxN];
int a[kMaxN], n, g, b, d, m;
int C() {
  	int r = 0; 
  	b -= e[1].x;
  	for (int i = 1; i < n;) {
    	if (b < 0) {
      		return -1;
    	}
    	if (e[e[i].p].x - e[i].x <= g) {
      		int v = 0;
			if (e[e[i].p].x - e[i].x - b > v) {
				v = e[e[i].p].x - e[i].x - b;
			}
      		r += v * e[i].y;
      		b += v - (e[e[i].p].x - e[i].x);
      		i = e[i].p;
    	} else {
      		r += 1LL * (g - b) * e[i].y;
      		b = g - (e[i + 1].x - e[i].x);
      		i++;
    	}
  	}
  	return b < 0 ? -1 : r;
}
signed main() {
  	cin >> n >> g >> b >> d;
  	for (int i = 1; i <= n; i++) {
    	cin >> e[i].x >> e[i].y;
  	}
  	sort(e + 1, e + 1 + n);
  	e[++n] = {d};
  	for (int i = 1; i <= n; i++) {
    	for (; m && e[i].y <= e[a[m]].y; m--) {
      		e[a[m]].p = i;
    	}
    	a[++m] = i;
  	}
  	cout << C();
  	return 0;
}
